import{_ as l,o as e,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const q=JSON.parse('{"title":"中医通鉴 · 通用版改造评估报告","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/通用版改造评估报告.md","filePath":"tcm-data/通用版改造评估报告.md","lastUpdated":null}'),s={name:"tcm-data/通用版改造评估报告.md"};function i(o,t,r,d,u,h){return e(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="中医通鉴-·-通用版改造评估报告" tabindex="-1">中医通鉴 · 通用版改造评估报告 <a class="header-anchor" href="#中医通鉴-·-通用版改造评估报告" aria-label="Permalink to &quot;中医通鉴 · 通用版改造评估报告&quot;">​</a></h1><blockquote><p>评估日期：2026-06-10 原始库：中医通鉴（72个md文件，~9125行） 个人引用：共371处&quot;不同类型患者&quot;引用，分布在44个文件中</p></blockquote><hr><h2 id="一、库的规模与个人化程度" tabindex="-1">一、库的规模与个人化程度 <a class="header-anchor" href="#一、库的规模与个人化程度" aria-label="Permalink to &quot;一、库的规模与个人化程度&quot;">​</a></h2><h3 id="_1-1-基础数据" tabindex="-1">1.1 基础数据 <a class="header-anchor" href="#_1-1-基础数据" aria-label="Permalink to &quot;1.1 基础数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:center;">数值</th></tr></thead><tbody><tr><td style="text-align:left;">总文件数（md）</td><td style="text-align:center;">72</td></tr><tr><td style="text-align:left;">总行数</td><td style="text-align:center;">~9,125</td></tr><tr><td style="text-align:left;">涉及不同类型患者的文件</td><td style="text-align:center;">44 / 72（61%）</td></tr><tr><td style="text-align:left;">总引用次数</td><td style="text-align:center;">371次</td></tr><tr><td style="text-align:left;">完全围绕不同类型患者的文件</td><td style="text-align:center;">4个（独立重构）</td></tr><tr><td style="text-align:left;">理论中穿插个人引用的文件</td><td style="text-align:center;">~30个（需逐处修改）</td></tr><tr><td style="text-align:left;">0引用的可保留文件</td><td style="text-align:center;">~28个（直接过）</td></tr></tbody></table><h3 id="_1-2-按个人化程度分类" tabindex="-1">1.2 按个人化程度分类 <a class="header-anchor" href="#_1-2-按个人化程度分类" aria-label="Permalink to &quot;1.2 按个人化程度分类&quot;">​</a></h3><p><strong>第一类：完全围绕个人（4个文件，需整体重建）</strong></p><ul><li>08-实战案例/01-患者（男）辨证案例.md（119行）</li><li>08-实战案例/02-患者（女）辨证案例.md（114行）</li><li>09-医易同源/06-患者（男）患者（女）医易辨证实战.md（153行）</li><li>11-八字命理/01-患者（男）患者（女）八字深层分析.md（140行） → 小计：~526行，占6%</li></ul><p><strong>第二类：重度穿插（12个文件，10-22处引用）</strong></p><ul><li>跨病证索引/03-气血水湿.md（18处）</li><li>医易同源/六十四卦上下经（22+17=39处）</li><li>医易同源/八卦与五脏（12处）、京氏易八宫（17+7=24处）</li><li>五运六气/01-总纲（16处）、03-丁未年（12处）</li><li>十二消息卦（12处）、身心同调（11处）</li><li>方药剂量/01-经方剂量考（12处）</li><li>食疗/药食同源（11处） → 小计：~390处，高度定制，每文件需5-20分钟精修</li></ul><p><strong>第三类：轻度穿插（~28个文件，1-9处引用）</strong></p><ul><li>明清各医家文件</li><li>近现代各医家文件</li><li>跨病证索引各文件</li><li>先秦两汉/03-金匮要略（3处） → 小计：每处改法相似，可批量处理</li></ul><p><strong>第四类：零引用（28个文件）</strong></p><ul><li>02-魏晋隋唐全部（0处）</li><li>01-先秦两汉大部分（0处）</li><li>03-宋金元大部分（0处）</li><li>04-明清部分（0处）</li><li>05-近现代部分（0处） → 直接保留，不需修改</li></ul><hr><h2 id="二、问题回答" tabindex="-1">二、问题回答 <a class="header-anchor" href="#二、问题回答" aria-label="Permalink to &quot;二、问题回答&quot;">​</a></h2><h3 id="q1-时间评估" tabindex="-1">Q1: 时间评估 <a class="header-anchor" href="#q1-时间评估" aria-label="Permalink to &quot;Q1: 时间评估&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">修改类型</th><th style="text-align:center;">预估工作量</th><th style="text-align:center;">预计时间</th></tr></thead><tbody><tr><td style="text-align:left;">4个独立文件重建</td><td style="text-align:center;">每文件重写框架+示例替换</td><td style="text-align:center;">30-45分钟</td></tr><tr><td style="text-align:left;">12个重度穿插文件精修</td><td style="text-align:center;">每处改为通用表述</td><td style="text-align:center;">45-70分钟</td></tr><tr><td style="text-align:left;">28个轻度穿插文件批量改</td><td style="text-align:center;">搜索替换+少量上下文调整</td><td style="text-align:center;">20-30分钟</td></tr><tr><td style="text-align:left;">00-索引总纲调整</td><td style="text-align:center;">去掉个人引用，更新导航</td><td style="text-align:center;">10-15分钟</td></tr><tr><td style="text-align:left;"><strong>总计纯修改时间</strong></td><td style="text-align:center;"></td><td style="text-align:center;"><strong>1.5-2.5小时</strong></td></tr><tr><td style="text-align:left;">审校+一致性检查</td><td style="text-align:center;">通读关键文件确认无遗漏</td><td style="text-align:center;">30-45分钟</td></tr><tr><td style="text-align:left;"><strong>总工时（AI辅助）</strong></td><td style="text-align:center;"></td><td style="text-align:center;"><strong>2-3小时</strong></td></tr></tbody></table><blockquote><p><strong>结论：用 AI 工具（批量替换+逐处审校），3小时内可完成全库脱敏。</strong></p></blockquote><p>注意：这是&quot;脱敏&quot;时间（去掉个人引用），不是&quot;重建知识深度&quot;的时间——知识框架本身是完整的，不需要重写中医理论。</p><h3 id="q2-结构方案——通用版怎么组织" tabindex="-1">Q2: 结构方案——通用版怎么组织？ <a class="header-anchor" href="#q2-结构方案——通用版怎么组织" aria-label="Permalink to &quot;Q2: 结构方案——通用版怎么组织？&quot;">​</a></h3><p><strong>原有结构（完全保留，0改动）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>00-索引总纲.md               ← 只改注释性文字</span></span>
<span class="line"><span>01-先秦两汉/                 ← 全部保留</span></span>
<span class="line"><span>02-魏晋隋唐/                 ← 全部保留</span></span>
<span class="line"><span>03-宋金元/                   ← 2个文件轻度修改</span></span>
<span class="line"><span>04-明清/                     ← 5个文件轻度修改</span></span>
<span class="line"><span>05-近现代/                   ← 7个文件轻度修改</span></span>
<span class="line"><span>06-跨病证索引/               ← 10个文件重度/轻度修改</span></span>
<span class="line"><span>07-食疗养生/                 ← 3个文件轻度修改</span></span>
<span class="line"><span>08-实战案例/                 ← 2个文件完全重建（改为通用案例）</span></span>
<span class="line"><span>09-医易同源/                 ← 11个文件重度修改</span></span>
<span class="line"><span>10-五运六气/                 ← 3个文件重度修改</span></span>
<span class="line"><span>11-八字命理/                 ← 完全重建（或改为附录）</span></span>
<span class="line"><span>12-方药剂量/                 ← 1个文件轻度修改</span></span>
<span class="line"><span>99-网站部署.md               ← 完全保留</span></span></code></pre></div><p><strong>直接保留的部分（不需要任何改动）：</strong></p><ul><li>01-先秦两汉/（除金匮要略3处外，基本全保留）</li><li>02-魏晋隋唐/（全部保留）</li><li>03-宋金元/01-易水学派、02-河间学派、05-小儿药证直诀（全保留）</li><li>04-明清/01-景岳全书、04-温病学派、05-徐灵胎、07-张锡纯、08-本草纲目（全保留）</li><li>05-近现代/06-刘力红、07-邓铁涛、08-朱良春、10-黄煌、11-胡希恕（全保留）</li><li>12-方药剂量/（仅改少量个人引用）</li><li>99-网站部署.md（全保留）</li></ul><p><strong>共约28个文件完全不需要改动。</strong></p><h3 id="q3-内容替代方案" tabindex="-1">Q3: 内容替代方案 <a class="header-anchor" href="#q3-内容替代方案" aria-label="Permalink to &quot;Q3: 内容替代方案&quot;">​</a></h3><p>当前模式 → 改为通用模式的映射方案：</p><table tabindex="0"><thead><tr><th style="text-align:left;">原文模式</th><th style="text-align:left;">通用替代</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;该男性患者&quot; / &quot;患者（女）&quot;</td><td style="text-align:left;">删除或改为&quot;某患者&quot; / &quot;临床举例&quot;</td></tr><tr><td style="text-align:left;">&quot;患者症状→XX医家分析&quot;</td><td style="text-align:left;">&quot;典型症状举例→XX医家分析&quot; 或删除个性化标注列</td></tr><tr><td style="text-align:left;">&quot;患者（男）核心病机&quot;</td><td style="text-align:left;">&quot;此病机常见于：脾肾阳虚型体质&quot;</td></tr><tr><td style="text-align:left;">&quot;患者处方：温潜黄芽天魂汤&quot;</td><td style="text-align:left;">&quot;处方举例：温潜黄芽天魂汤（适用于水寒土湿证）&quot;</td></tr><tr><td style="text-align:left;">&quot;对不同类型患者相关&quot; 列</td><td style="text-align:left;">改为 &quot;对应症状举例&quot; 或整列删除</td></tr><tr><td style="text-align:left;">&quot;患者（男）vs患者（女）对比&quot;</td><td style="text-align:left;">&quot;同病异治：同一症状的不同病机对比&quot;</td></tr><tr><td style="text-align:left;">&quot;患者（男）面诊/患者（女）面诊&quot;</td><td style="text-align:left;">&quot;典型面诊案例&quot;</td></tr><tr><td style="text-align:left;">文件标题含两人名字</td><td style="text-align:left;">改为通用标题（如&quot;八字与体质分析示例&quot;）</td></tr></tbody></table><p><strong>关键原则：</strong></p><ul><li>不删除理论内容，只改标签</li><li>所有个性化数据（症状、处方）保留为&quot;示例数据&quot;</li><li>对比表格保留框架，把&quot;不同类型患者&quot;替换为&quot;案例A/案例B&quot;或&quot;男性/女性示例&quot;</li></ul><h3 id="q4-推荐路径-——-a-加密码锁-vs-c-重建通用版-vs-a-c" tabindex="-1">Q4: 推荐路径 —— A（加密码锁） vs C（重建通用版） vs A+C <a class="header-anchor" href="#q4-推荐路径-——-a-加密码锁-vs-c-重建通用版-vs-a-c" aria-label="Permalink to &quot;Q4: 推荐路径 —— A（加密码锁） vs C（重建通用版） vs A+C&quot;">​</a></h3><p><strong>推荐：A+C 混合方案</strong></p><p>理由：</p><ol><li><p><strong>纯A（加密码锁）的风险</strong>：加密码锁只能防&quot;路人&quot;不能防&quot;用心人&quot;。既然数据已经是你个人健康隐私（八字、体质、住址、家庭信息），加密码锁只是心理安慰。一旦泄露，就是完整的个人健康档案。</p></li><li><p><strong>纯C（全部重建）的成本</strong>：4个完全围绕个人的文件确实需要重建，但理论框架文件中的371处引用，大部分是&quot;一句话式&quot;的旁注（&quot;这正是患者的核心病机&quot;之类），完全可以通过搜索替换+人工审校快速完成，并不需要重写整篇。</p></li><li><p><strong>A+C混合是最优解</strong>：</p><ul><li>A：立即执行（今天），给当前库加密码锁，防止意外泄露</li><li>C：逐步推进（本周内完成），去掉个人引用后公开</li></ul></li></ol><h3 id="q5-最快方案——混合方案第一步" tabindex="-1">Q5: 最快方案——混合方案第一步 <a class="header-anchor" href="#q5-最快方案——混合方案第一步" aria-label="Permalink to &quot;Q5: 最快方案——混合方案第一步&quot;">​</a></h3><p><strong>第一步最应该做的事：立即执行A（加密码锁），保护现有数据</strong></p><p>具体操作：</p><ol><li>Vitepress部署时加password保护（用vitepress-plugin-pagefind或nginx basic auth）</li><li>同时在仓库根目录加 .htaccess 或 nginx配置</li><li>这一步只需5-10分钟，立竿见影</li></ol><p><strong>然后马上开始的第二步（C的起点）：</strong> 先从最简单、改动最小的文件入手——</p><ol><li>在28个零引用文件上确认&quot;无问题&quot;</li><li>批量替换所有&quot;该男性患者&quot;→&quot;患者&quot;、&quot;患者（女）&quot;→&quot;患者&quot;、&quot;不同类型患者&quot;→&quot;患者&quot;</li><li>再逐个处理重度穿插的文件</li></ol><hr><h2 id="三、具体工作量拆解" tabindex="-1">三、具体工作量拆解 <a class="header-anchor" href="#三、具体工作量拆解" aria-label="Permalink to &quot;三、具体工作量拆解&quot;">​</a></h2><h3 id="phase-1-立即执行-a方案-加访问控制" tabindex="-1">Phase 1: 立即执行（A方案）- 加访问控制 <a class="header-anchor" href="#phase-1-立即执行-a方案-加访问控制" aria-label="Permalink to &quot;Phase 1: 立即执行（A方案）- 加访问控制&quot;">​</a></h3><ul><li>加密码锁：10分钟</li><li>加robots.txt禁止爬虫：5分钟</li><li>共：15分钟</li></ul><h3 id="phase-2-批量替换-c方案第1步-28个轻度文件" tabindex="-1">Phase 2: 批量替换（C方案第1步）- 28个轻度文件 <a class="header-anchor" href="#phase-2-批量替换-c方案第1步-28个轻度文件" aria-label="Permalink to &quot;Phase 2: 批量替换（C方案第1步）- 28个轻度文件&quot;">​</a></h3><ul><li>4种标准替换模式 × 28个文件</li><li>预计：20-30分钟</li></ul><h3 id="phase-3-精修-c方案第2步-12个重度文件" tabindex="-1">Phase 3: 精修（C方案第2步）- 12个重度文件 <a class="header-anchor" href="#phase-3-精修-c方案第2步-12个重度文件" aria-label="Permalink to &quot;Phase 3: 精修（C方案第2步）- 12个重度文件&quot;">​</a></h3><ul><li>逐个文件审校，每文件5-15分钟</li><li>预计：45-70分钟</li></ul><h3 id="phase-4-重建-c方案第3步-4个完全个性化文件" tabindex="-1">Phase 4: 重建（C方案第3步）- 4个完全个性化文件 <a class="header-anchor" href="#phase-4-重建-c方案第3步-4个完全个性化文件" aria-label="Permalink to &quot;Phase 4: 重建（C方案第3步）- 4个完全个性化文件&quot;">​</a></h3><ul><li>保留框架，替换为通用案例</li><li>预计：30-45分钟</li></ul><h3 id="phase-5-审校" tabindex="-1">Phase 5: 审校 <a class="header-anchor" href="#phase-5-审校" aria-label="Permalink to &quot;Phase 5: 审校&quot;">​</a></h3><ul><li>全文搜索&quot;患者（男）&quot;、&quot;患者（女）&quot;确保0遗漏</li><li>导航/链接更新</li><li>预计：20-30分钟</li></ul><p><strong>总计：2-3小时（AI辅助全流程）</strong></p><hr><h2 id="四、保留的价值" tabindex="-1">四、保留的价值 <a class="header-anchor" href="#四、保留的价值" aria-label="Permalink to &quot;四、保留的价值&quot;">​</a></h2><p>值得强调的是，这套知识库的<strong>理论框架、医家分析、方剂整理、跨病证索引</strong>本身就是高质量的通用中医资料。去掉个人标签后：</p><ul><li>可公开分享到社区</li><li>可用作中医学习资料</li><li>可作为个人知识管理（PKM）的样板</li><li>网站部署方案仍然有效</li></ul><p>目前的个人引用就像&quot;贴在一本教科书上的便利贴&quot;——抽掉便利贴，教科书依然完整。</p>`,60)])])}const c=l(s,[["render",i]]);export{q as __pageData,c as default};
